import{_ as i,c as o,o as r,j as t,ag as n,a}from"./chunks/framework.S-Qvb3wi.js";const f=JSON.parse('{"title":"Moderator Guide","description":"","frontmatter":{"title":"Moderator Guide","lang":"en-GB","outline":"deep","lastUpdated":true,"search":false},"headers":[],"relativePath":"guide/moderator.md","filePath":"guide/moderator.md","lastUpdated":1754885626000}'),s={name:"guide/moderator.md"};function l(d,e,h,u,c,m){return r(),o("div",null,e[0]||(e[0]=[t("h1",{moderator:"",id:"moderator-s-guide",tabindex:"-1"},[a("Moderator's Guide "),t("a",{class:"header-anchor",href:"#moderator-s-guide","aria-label":`Permalink to "Moderator's Guide {moderator}"`},"​")],-1),n('<h2 id="general-information" tabindex="-1">What is the general information about moderation? <a class="header-anchor" href="#general-information" aria-label="Permalink to &quot;What is the general information about moderation? {#general-information}&quot;">​</a></h2><ul><li><strong>Read and understand all server rules</strong> (rough memorization recommended)</li><li><strong>Set server notifications</strong> to <em>&quot;Mentions Only&quot;</em> (recommended) or <em>&quot;All Messages&quot;</em></li><li><strong>Know all server channels</strong> and their purposes</li></ul><h3 id="staff-strikes-system" tabindex="-1">Staff Strikes System <a class="header-anchor" href="#staff-strikes-system" aria-label="Permalink to &quot;Staff Strikes System&quot;">​</a></h3><ul><li>Given for improper staff behavior or rule violations</li><li>3 strikes = demotion</li></ul><h3 id="chat-management" tabindex="-1">Chat Management <a class="header-anchor" href="#chat-management" aria-label="Permalink to &quot;Chat Management&quot;">​</a></h3><ul><li>Direct conversations to appropriate channels</li><li><strong>Prevent</strong> spam/flooding with gifs/images in chat channels</li></ul><h3 id="ticket-support" tabindex="-1">Ticket Support <a class="header-anchor" href="#ticket-support" aria-label="Permalink to &quot;Ticket Support&quot;">​</a></h3><ul><li><strong>Respond quickly</strong> to support tickets</li><li>ONE staff member per ticket only</li><li>First staff member handles and closes the ticket</li></ul><h3 id="moderation-actions" tabindex="-1">Moderation Actions <a class="header-anchor" href="#moderation-actions" aria-label="Permalink to &quot;Moderation Actions&quot;">​</a></h3><ul><li>Use punishment commands where the incident occurred or in <code>#・staff-cmd</code></li><li>Always check previous warnings with <code>!warnings @mention</code></li></ul><h3 id="general-guidelines" tabindex="-1">General Guidelines <a class="header-anchor" href="#general-guidelines" aria-label="Permalink to &quot;General Guidelines&quot;">​</a></h3><ul><li>Maintain a family-friendly environment</li><li>Use common sense</li><li><strong>Have fun 😃</strong></li></ul><h2 id="punishment" tabindex="-1">What are the punishment guidelines for moderators? <a class="header-anchor" href="#punishment" aria-label="Permalink to &quot;What are the punishment guidelines for moderators? {#punishment}&quot;">​</a></h2><h3 id="level-1-violations" tabindex="-1">Level 1 Violations <a class="header-anchor" href="#level-1-violations" aria-label="Permalink to &quot;Level 1 Violations&quot;">​</a></h3><ul><li><p><strong>Spam</strong></p><ul><li>1st Offense: Warn + Delete their messages</li><li>2nd Offense: 30-minute Mute + Delete their messages</li><li>3rd Offense: 1-day Mute + Delete their messages</li></ul></li><li><p><strong>Not Listening After a Warning</strong></p><ul><li>1st Offense: Warn</li><li>2nd Offense: Warn + 1-hour Mute</li><li>3th Offense: Warn + 6-hour Mute</li><li>4th Offense: Warn + 3-day Mute</li></ul></li><li><p><strong>Using the Wrong Channel</strong></p><ul><li>1st Offense: Verbal Warn</li><li>2nd Offense: Warn</li><li>3rd Offense: Warn + 1-hour Mute</li><li>4th Offense: Warn + 6-hour Mute</li></ul></li><li><p><strong>Repeatedly Asking for Leaks in the Wrong Place</strong></p><ul><li>1st Offense: Warn + Delete their messages</li><li>2nd Offense: Warn + Delete their messages</li><li>3rd Offense: Warn + 1-hour Mute + Delete their messages</li><li>4th Offense: Warn + 12-hour Mute + Delete their messages</li><li>5th Offense: Warn + 3-day Mute + Delete their messages</li></ul></li></ul><h3 id="level-2-violations" tabindex="-1">Level 2 Violations <a class="header-anchor" href="#level-2-violations" aria-label="Permalink to &quot;Level 2 Violations&quot;">​</a></h3><ul><li><p><strong>Self-Promotion</strong></p><ul><li>1st Offense: Warn + Delete their messages</li><li>2nd Offense: Warn + 24-hour Mute + Delete their messages</li><li>3rd Offense: 3-day Mute + Delete their messages</li></ul></li><li><p><strong>Harassment</strong></p><ul><li>1st Offense: Warn + 1-hour Mute + Delete their messages</li><li>2nd Offense: Warn + 12-hour Mute + Delete their messages</li><li>3rd Offense: Kick + Delete their messages</li></ul></li><li><p><strong>Hate Speech/Discrimination</strong></p><ul><li>1st Offense: Warn + 1-hour Mute + Delete their messages</li><li>2nd Offense: Warn + 12-hour Mute + Delete their messages</li><li>3rd Offense: Kick + Delete their messages</li></ul></li><li><p><strong>Trolling/Disruptive Behavior</strong></p><ul><li>1st Offense: Warn + Delete their messages if necessary</li><li>2nd Offense: Warn + 1-hour Mute + Delete their messages if necessary</li><li>3rd Offense: Warn + 12-hour Mute + Delete their messages if necessary</li><li>4th Offense: Kick + Delete their messages if necessary</li></ul></li><li><p><strong>Undermining 6ure</strong></p><ul><li>1st Offense: Warn</li><li>2nd Offense: Kick</li><li>3rd Offense: Ban</li></ul></li><li><p><strong>Spam Ping</strong></p><ul><li>1st Offense: Warn + Delete their messages</li><li>2nd Offense: Kick + Delete their messages</li><li>3rd Offense: Ban</li></ul></li><li><p><strong>Bypassing Punishments</strong> <em>(e.g., using alt accounts to avoid mutes, kicks, or bans)</em></p><ul><li>Immediate Ban without warning</li></ul></li><li><p><strong>Zero-Tolerance Violations (Immediate Ban)</strong></p><ul><li>NSFW/Gore Content</li><li>Doxxing</li><li>Copying/Replicating 6ure</li><li>Breaking Discord ToS</li><li>Racism</li><li>Leaking Personal Information</li></ul></li></ul><p><strong>Ban Duration Guide</strong></p><table tabindex="0"><thead><tr><th>Type</th><th style="text-align:center;">Duration</th></tr></thead><tbody><tr><td><strong>DM Advertising</strong></td><td style="text-align:center;">1-Day</td></tr><tr><td><strong>Suicide Encouragement</strong></td><td style="text-align:center;">1-Week</td></tr><tr><td><strong>Doxxing</strong></td><td style="text-align:center;">Permanent</td></tr><tr><td><strong>NSFW Content</strong></td><td style="text-align:center;">Permanent</td></tr><tr><td><strong>Racism</strong></td><td style="text-align:center;">Permanent</td></tr><tr><td>Always check user history with <code>!warnings (user)</code> before taking action</td><td style="text-align:center;"></td></tr></tbody></table><h2 id="responsibilities" tabindex="-1">What are the responsibilities of a moderator? <a class="header-anchor" href="#responsibilities" aria-label="Permalink to &quot;What are the responsibilities of a moderator? {#responsibilities}&quot;">​</a></h2><h3 id="handling-tickets" tabindex="-1"><strong>Handling Tickets</strong> <a class="header-anchor" href="#handling-tickets" aria-label="Permalink to &quot;**Handling Tickets**&quot;">​</a></h3><ul><li><p>Tickets are a primary way for members to seek support. These include:</p><ul><li>Claim level &amp; boost perks</li><li>Report a member</li><li>Questions or concerns</li><li>Applying for staff or Partner Manager</li><li>Asking to partner</li><li>Sponsoring an event or giveaway</li></ul></li><li><p><strong>How to handle tickets:</strong></p><ul><li><strong>Respond Quickly:</strong> Address tickets as soon as possible.</li><li><strong>One Moderator per Ticket:</strong> Only one staff member should handle each ticket. If you&#39;re unable to assist further, transfer the ticket to another staff member using <code>/transfer</code> command.</li><li><strong>Professional Tone:</strong> Always respond politely, respectfully, and professionally.</li><li><strong>Closing Tickets:</strong> Close tickets once they are resolved. This includes when the member leaves the ticket empty/no response.</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>You are <strong>required</strong> to warn any member that leaves a ticket empty or no follow-up.</p></div><h3 id="deleting-messages" tabindex="-1">Deleting Messages <a class="header-anchor" href="#deleting-messages" aria-label="Permalink to &quot;Deleting Messages&quot;">​</a></h3><p><strong>When to Delete Messages:</strong></p><ul><li>NSFW content</li><li>Hate speech</li><li>Racist or discriminatory remarks</li><li>Spam or self-promotion</li><li>Messages in the wrong channels</li></ul><h3 id="activity-expectations" tabindex="-1">Activity Expectations <a class="header-anchor" href="#activity-expectations" aria-label="Permalink to &quot;Activity Expectations&quot;">​</a></h3><p><strong>Minimum Activity:</strong> 24-hour per week</p><p><strong>Trial Moderator Requirements:</strong></p><ul><li>Be active and engage in the community.</li><li>Assist members and moderate channels.</li><li>Use at least 5 mod commands appropriately.</li></ul><h3 id="general-responsibilities" tabindex="-1">General Responsibilities <a class="header-anchor" href="#general-responsibilities" aria-label="Permalink to &quot;General Responsibilities&quot;">​</a></h3><p><strong>Core Duties:</strong></p><ul><li>Enforce server rules and guidelines.</li><li>Monitor messages and remove rule-breaking content.</li><li>Handle user reports, tickets, and conflicts.</li><li>Maintain a welcoming and positive community atmosphere.</li></ul><p><strong>Key Skills:</strong></p><ul><li>Strong communication skills.</li><li>Conflict resolution.</li><li>Fair judgment and empathy.</li><li>Patience and professionalism.</li></ul><h2 id="moderation-commands" tabindex="-1">What are the moderation commands? <a class="header-anchor" href="#moderation-commands" aria-label="Permalink to &quot;What are the moderation commands? {#moderation-commands}&quot;">​</a></h2><ul><li><code>!warn @mention/id reason</code> - Issues a warning to the mentioned user.</li><li><code>!sp @mention/id proof</code> - Set proof to the most recent case tied to your action. (Attach a file or link/message link)</li><li><code>!mute @mention/id 1h reason</code> - Mutes the mentioned user for 1 hour. <em>(Default: 1 hour)</em></li><li><code>!tempmute @mention/id 1h reason</code> - Temporarily mutes the mentioned user for 1 hour. <em>(Default: 1 hour)</em></li><li><code>!ban @mention/id reason</code> - Bans the mentioned user. <em>(Default: No duration)</em></li><li><code>!tempban @mention/id 1d reason</code> - Temporarily bans the mentioned user for 1 day. <em>(Default: Unknown duration)</em></li><li><code>!warnings @mention/id</code> - Displays the warning history of the mentioned user.</li></ul><p><strong>Note:</strong> These are examples of the basic commands you&#39;ll use for moderation.</p><h2 id="server-related" tabindex="-1">Server Related <a class="header-anchor" href="#server-related" aria-label="Permalink to &quot;Server Related {#server-related}&quot;">​</a></h2><h3 id="ticket" tabindex="-1">Ticket <a class="header-anchor" href="#ticket" aria-label="Permalink to &quot;Ticket&quot;">​</a></h3><p>If you claimed a ticket, please warn the member and close the ticket if no response are given for over 12 hours. This would help the server be less clogged.</p><h3 id="booster-role" tabindex="-1">Booster Role <a class="header-anchor" href="#booster-role" aria-label="Permalink to &quot;Booster Role&quot;">​</a></h3><p>When a user opens a ticket to claim their custom role, please do the following:</p><ol><li><strong>Verify Booster Status</strong>: First, confirm that the member has boosted the server at least <strong>twice</strong> (<code>2x</code>). This is a strict requirement.</li><li><strong>Whitelist the Member</strong>: Use the new command to grant them access to the role creation panel. (<code>/boosterrole whitelist</code>)</li></ol><p><strong>Command:</strong> Using this command on a valid 2x booster will allow them to use <code>/boosterrole manage</code>. Please familiarize yourselves with this new procedure.</p><h3 id="duplicate-requests" tabindex="-1">Duplicate requests <a class="header-anchor" href="#duplicate-requests" aria-label="Permalink to &quot;Duplicate requests&quot;">​</a></h3><p>Request duplicates can be monitored through: <a href="https://discord.com/channels/1118862694980788276/1395469507014951063" target="_blank" rel="noreferrer">#・request-log</a>. You can simply <strong>Delete</strong> the detected duplicate request, or <strong>Ignore</strong> it (if it made some mistake or other reasons).</p><h3 id="unable-to-click-download-button-in-presets" tabindex="-1">Unable to click download button in Presets <a class="header-anchor" href="#unable-to-click-download-button-in-presets" aria-label="Permalink to &quot;Unable to click download button in Presets&quot;">​</a></h3><p>If buttons in certain threads in <code>#・presets</code> went greyed out, it means the thread is archived. You may run the command <code>/reopen</code> to unarchive all archived threads.</p><h3 id="_1-month-old-account-restriction-whitelist" tabindex="-1">1-month old account restriction whitelist <a class="header-anchor" href="#_1-month-old-account-restriction-whitelist" aria-label="Permalink to &quot;1-month old account restriction whitelist&quot;">​</a></h3><p>To whitelist a member to bypass the <code>#・preset</code> download 1-month old account restriction, follow the steps below to ensure they&#39;re legit and not suspicious.</p><p><strong>Requirements to Get Whitelisted</strong></p><ul><li>The member <strong>must provide</strong>: <ul><li>A screenshot of their TikTok profile.</li><li>The account must be an editing account.</li><li>Make sure the screenshot clearly shows &quot;<strong>Edit profile</strong>&quot; — this confirms it’s their own account.</li></ul></li></ul><p>If you don’t see &quot;Edit profile&quot;, it’s most likely fake.</p><p><strong>How to Check If They&#39;re Suspicious</strong></p><ul><li>Before approving, do the following: <ul><li>Search up their TikTok username directly on TikTok.</li><li>Check if the account looks real: consistent content, normal follower/following ratio, not freshly made.</li><li>If something feels off (no posts, suspicious bio, reused content), ask follow-up questions or deny the request. The command: <code>/leak whitelist</code></li></ul></li></ul>',56)]))}const p=i(s,[["render",l]]);export{f as __pageData,p as default};
